import { useState, useEffect, useCallback } from "react";
import type { UseNoteFiltersProps } from "@/features/notesapp/types/notes-hooks";
import type { NoteWithRelations } from "@/shared/types/notes";

export type UseNoteFiltersResult = {
  searchQuery: string;
  setSearchQuery: (q: string) => void;
  debouncedSearchQuery: string;
  filterPinned: boolean | undefined;
  setFilterPinned: (v: boolean | undefined) => void;
  filterArchived: boolean | undefined;
  setFilterArchived: (v: boolean | undefined) => void;
  filterFavorite: boolean | undefined;
  setFilterFavorite: (v: boolean | undefined) => void;
  filterTagIds: string[];
  setFilterTagIds: (ids: string[]) => void;
  highlightTagId: string | null;
  setHighlightTagId: (id: string | null) => void;
  page: number;
  setPage: (p: number | ((curr: number) => number)) => void;
  pageSize: number;
  setPageSize: (s: number) => void;
  handleFilterByTag: (tagId: string, setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => void;
  handleToggleFavoritesFilter: (setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => void;
};

export function useNoteFilters({ settings, updateSettings: _updateSettings }: UseNoteFiltersProps): UseNoteFiltersResult {
  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchQuery);
  const [filterPinned, setFilterPinned] = useState<boolean | undefined>(undefined);
  const [filterArchived, setFilterArchived] = useState<boolean | undefined>(undefined);
  const [filterFavorite, setFilterFavorite] = useState<boolean | undefined>(undefined);
  const [filterTagIds, setFilterTagIds] = useState<string[]>([]);
  const [highlightTagId, setHighlightTagId] = useState<string | null>(null);

  // Pagination
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(24);

  // Debounce search
  useEffect((): void | (() => void) => {
    const timer = setTimeout((): void => {
      setDebouncedSearchQuery(searchQuery);
    }, 250);
    return (): void => clearTimeout(timer);
  }, [searchQuery]);

  // Reset page when filters change
  useEffect((): void => {

    setPage(1);
  }, [
    debouncedSearchQuery,
    filterPinned,
    filterArchived,
    filterTagIds,
    settings.selectedFolderId,
    settings.sortBy,
    settings.sortOrder,
    settings.selectedNotebookId,
  ]);

  // Clear highlight tag
  useEffect((): void | (() => void) => {
    if (!highlightTagId) return;
    const timer = setTimeout((): void => {
      setHighlightTagId(null);
    }, 2000);
    return (): void => clearTimeout(timer);
  }, [highlightTagId]);

  const handleFilterByTag = useCallback((tagId: string, setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void): void => {
    setSelectedFolderId(null);
    setFilterTagIds([tagId]);
    setSearchQuery("");
    setSelectedNote(null);
    setIsEditing(false);
    setHighlightTagId(tagId);
  }, []);

  const handleToggleFavoritesFilter = useCallback((setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void): void => {
    setFilterFavorite((prev: boolean | undefined) => (prev ? undefined : true));
    setSelectedFolderId(null);
    setSelectedNote(null);
    setIsEditing(false);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    debouncedSearchQuery,
    filterPinned,
    setFilterPinned,
    filterArchived,
    setFilterArchived,
    filterFavorite,
    setFilterFavorite,
    filterTagIds,
    setFilterTagIds,
    highlightTagId,
    setHighlightTagId,
    page,
    setPage,
    pageSize,
    setPageSize,
    handleFilterByTag,
    handleToggleFavoritesFilter,
  };
}

"use client";

import { Button, Input, DynamicFilters, useToast, Label, ListPanel, SectionPanel, Table, TableBody, TableCell, TableHead, TableHeader, TableRow, Pagination, StatusBadge, ConfirmDialog, AdminPageLayout, RefreshButton, type FilterField } from "@/shared/ui";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useEffect, useMemo, useState, type ChangeEvent } from "react";
import { useSearchParams } from "next/navigation";
import { useSystemLogs, useSystemLogMetrics, useMongoDiagnostics } from "@/features/observability/hooks/useLogQueries";
import { useClearLogsMutation, useRebuildIndexesMutation } from "@/features/observability/hooks/useLogMutations";

import { RefreshCcw, Trash2, Copy } from "lucide-react";
import type { SystemLogMetrics, SystemLogRecord, SystemLogLevel, AiInsightRecord } from "@/shared/types";

const levelOptions: Array<{ value: SystemLogLevel | "all"; label: string }> = [
  { value: "all", label: "All levels" },
  { value: "error", label: "Errors" },
  { value: "warn", label: "Warnings" },
  { value: "info", label: "Info" },
];

type MongoIndexInfo = {
  name?: string;
  key: Record<string, unknown>;
};

type MongoCollectionIndexStatus = {
  name: string;
  expected: MongoIndexInfo[];
  existing: MongoIndexInfo[];
  missing: MongoIndexInfo[];
  extra: MongoIndexInfo[];
  error?: string;
};

interface MongoDiagnosticsData {
  collections?: MongoCollectionIndexStatus[];
  generatedAt?: string;
}

const formatTimestamp = (value: Date | string): string => {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return "—";
  return date.toLocaleString();
};

const formatDateParam = (value: string, endOfDay: boolean = false): string | null => {
  if (!value) return null;
  const suffix = endOfDay ? "T23:59:59.999" : "T00:00:00.000";
  const date = new Date(`${value}${suffix}`);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
};

export default function SystemLogsPage(): React.JSX.Element {
  const { toast } = useToast();
  const searchParams = useSearchParams();

  const [level, setLevel] = useState<SystemLogLevel | "all">(() => {
    const p = searchParams?.get("level");
    if (p && levelOptions.some((option: (typeof levelOptions)[number]) => option.value === p)) {
      return p as SystemLogLevel | "all";
    }
    return "all";
  });

  const [query, setQuery] = useState(() => searchParams?.get("query") ?? "");
  const [source, setSource] = useState(() => searchParams?.get("source") ?? "");

  const [fromDate, setFromDate] = useState(() => {
    const p = searchParams?.get("from");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [toDate, setToDate] = useState(() => {
    const p = searchParams?.get("to");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [isClearLogsConfirmOpen, setIsClearLogsConfirmOpen] = useState(false);
  const [isRebuildIndexesConfirmOpen, setIsRebuildIndexesConfirmOpen] = useState(false);
  const [logInterpretations, setLogInterpretations] = useState<Record<string, AiInsightRecord>>({});

  const [page, setPage] = useState(1);
  const pageSize = 50;

  const filters = useMemo(() => ({
    page,
    pageSize,
    level,
    query,
    source,
    from: formatDateParam(fromDate),
    to: formatDateParam(toDate, true),
  }), [page, pageSize, level, query, source, fromDate, toDate]);

  const metricsFilters = useMemo(() => ({
    level,
    query,
    source,
    from: formatDateParam(fromDate),
    to: formatDateParam(toDate, true),
  }), [level, query, source, fromDate, toDate]);

  // Queries
  const logsQuery = useSystemLogs(filters);
  const metricsQuery = useSystemLogMetrics(metricsFilters);
  const mongoDiagnosticsQuery = useMongoDiagnostics();
  const insightsQuery = useQuery({
    queryKey: ["system", "logs", "insights"],
    queryFn: async () => {
      const res = await fetch("/api/system/logs/insights?limit=5");
      if (!res.ok) {
        const body = (await res.json().catch(() => null)) as { error?: string } | null;
        throw new Error(body?.error ?? "Failed to load log insights.");
      }
      return (await res.json()) as { insights: AiInsightRecord[] };
    },
  });

  const runInsightMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/system/logs/insights", { method: "POST" });
      const data = (await res.json().catch(() => null)) as { insight?: AiInsightRecord; error?: string } | null;
      if (!res.ok) {
        throw new Error(data?.error ?? "Failed to generate log insight.");
      }
      return data?.insight ?? null;
    },
    onSuccess: (insight: AiInsightRecord | null) => {
      if (insight) {
        toast("AI log insight generated.", { variant: "success" });
        void insightsQuery.refetch();
      }
    },
    onError: (error: unknown) => {
      toast(error instanceof Error ? error.message : "Failed to generate log insight.", { variant: "error" });
    },
  });

  const interpretLogMutation = useMutation({
    mutationFn: async (logId: string) => {
      const res = await fetch("/api/system/logs/interpret", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ logId }),
      });
      const data = (await res.json().catch(() => null)) as { insight?: AiInsightRecord; error?: string } | null;
      if (!res.ok) {
        throw new Error(data?.error ?? "Failed to interpret log.");
      }
      return data?.insight ?? null;
    },
    onSuccess: (insight: AiInsightRecord | null) => {
      if (!insight) return;
      const logId = insight.context?.logId;
      const key = typeof logId === "string" ? logId : insight.id;
      setLogInterpretations((prev: Record<string, AiInsightRecord>) => ({
        ...prev,
        [key]: insight,
      }));
      toast("AI interpretation added.", { variant: "success" });
    },
    onError: (error: unknown) => {
      toast(error instanceof Error ? error.message : "Failed to interpret log.", { variant: "error" });
    },
  });

  // Mutations
  const clearLogsMutation = useClearLogsMutation();
  const rebuildIndexesMutation = useRebuildIndexesMutation();

  useEffect(() => {
    if (logsQuery.error) toast(logsQuery.error.message, { variant: "error" });
  }, [logsQuery.error, toast]);

  useEffect(() => {
    if (metricsQuery.error) toast(metricsQuery.error.message, { variant: "error" });
  }, [metricsQuery.error, toast]);

  useEffect(() => {
    if (mongoDiagnosticsQuery.error) toast(mongoDiagnosticsQuery.error.message, { variant: "error" });
  }, [mongoDiagnosticsQuery.error, toast]);

  const logs = useMemo(() => logsQuery.data?.logs ?? [], [logsQuery.data]);
  const total = logsQuery.data?.total ?? 0;
  const metrics = metricsQuery.data?.metrics ?? null;
  const diagnostics = useMemo((): MongoCollectionIndexStatus[] => {
    const data = mongoDiagnosticsQuery.data as MongoDiagnosticsData | undefined;
    return data?.collections ?? [];
  }, [mongoDiagnosticsQuery.data]);
  const diagnosticsUpdatedAt = (mongoDiagnosticsQuery.data as MongoDiagnosticsData | undefined)?.generatedAt ?? null;

  const logsJson = useMemo(() => JSON.stringify(logs, null, 2), [logs]);

  const totalPages: number = useMemo((): number => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const handleClearLogs = async (): Promise<void> => {
    try {
      await clearLogsMutation.mutateAsync();
      toast("System logs cleared.", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to clear logs.", {
        variant: "error",
      });
    }
  };

  const handleRebuildMongoIndexes = async (): Promise<void> => {
    try {
      const result = (await rebuildIndexesMutation.mutateAsync()) as { created?: unknown[] };
      const createdCount = result?.created?.length ?? 0;
      toast(
        createdCount > 0
          ? `Rebuilt ${createdCount} index(es).`
          : "Mongo indexes already up to date.",
        { variant: "success" }
      );
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to rebuild indexes.", {
        variant: "error",
      });
    }
  };

  const getContextValue = (context: unknown, path: string): unknown => {
    if (!context || typeof context !== "object" || Array.isArray(context)) return null;
    let current: unknown = context;
    for (const key of path.split(".")) {
      if (!current || typeof current !== "object" || Array.isArray(current)) return null;
      current = (current as Record<string, unknown>)[key];
    }
    return current ?? null;
  };

  const levels = metrics?.levels ?? { error: 0, warn: 0, info: 0 };

  const filterFields: FilterField[] = [
    { key: "level", label: "Level", type: "select", options: [...levelOptions] },
    { key: "query", label: "Search", type: "text", placeholder: "Message or source" },
    { key: "source", label: "Source", type: "text", placeholder: "api/products, auth, etc." },
    { key: "fromDate", label: "From", type: "date" },
    { key: "toDate", label: "To", type: "date" },
  ];

  const handleFilterChange = (key: string, value: any): void => {
    setPage(1);
    if (key === "level") setLevel(value);
    if (key === "query") setQuery(value);
    if (key === "source") setSource(value);
    if (key === "fromDate") setFromDate(value);
    if (key === "toDate") setToDate(value);
  };

  const handleResetFilters = (): void => {
    setLevel("all");
    setQuery("");
    setSource("");
    setFromDate("");
    setToDate("");
    setPage(1);
  };

  return (
    <AdminPageLayout
      title="System Logs"
      description="Centralized error and warning events captured across the platform."
      mainActions={
        <>
          <Button
            variant="outline"
            size="sm"
            onClick={() => window.location.assign("/admin/settings/logging")}
          >
            Client Logging Settings
          </Button>
          <RefreshButton
            onRefresh={(): void => {
              void logsQuery.refetch();
              void metricsQuery.refetch();
            }}
            isRefreshing={logsQuery.isFetching || metricsQuery.isFetching}
          />
          <Button
            variant="outline"
            size="sm"
            className="gap-2"
            disabled={logs.length === 0}
            onClick={(): void => {
              void navigator.clipboard.writeText(logsJson).then(() => {
                toast("Copied to clipboard", { variant: "success" });
              });
            }}
          >
            <Copy className="h-4 w-4" />
            Copy
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => setIsClearLogsConfirmOpen(true)}
            className="border-red-500/40 text-red-200 hover:bg-red-500/10"
            disabled={logs.length === 0 || clearLogsMutation.isPending}
          >
            <Trash2 className="mr-2 h-4 w-4" />
            {clearLogsMutation.isPending ? "Clearing..." : "Clear Logs"}
          </Button>
        </>
      }
    >
      <ListPanel
        variant="flat"
        alerts={
          <>
            <ConfirmDialog
              open={isClearLogsConfirmOpen}
              onOpenChange={setIsClearLogsConfirmOpen}
              onConfirm={(): void => {
                void handleClearLogs();
              }}
              title="Clear System Logs"
              description="Are you sure you want to clear all system logs? This action cannot be undone."
              confirmText="Clear All"
              variant="destructive"
            />
            <ConfirmDialog
              open={isRebuildIndexesConfirmOpen}
              onOpenChange={setIsRebuildIndexesConfirmOpen}
              onConfirm={(): void => {
                void handleRebuildMongoIndexes();
              }}
              title="Rebuild Indexes"
              description="This will scan AI Paths collections and create missing indexes. Proceed?"
              confirmText="Rebuild"
            />
            <SectionPanel className="space-y-4">
              <div className="flex flex-wrap items-center justify-between gap-3">
                <div>
                  <div className="text-lg font-semibold text-white">Diagnostics</div>
                  <div className="text-xs text-gray-400">
                    Mongo index status for AI Paths runtime collections.
                  </div>
                </div>
                <div className="flex items-center gap-2 text-xs text-gray-500">
                  <span>
                    {diagnosticsUpdatedAt
                      ? `Updated ${formatTimestamp(diagnosticsUpdatedAt)}`
                      : "—"}
                  </span>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={(): void => {
                      void mongoDiagnosticsQuery.refetch();
                    }}
                    disabled={mongoDiagnosticsQuery.isFetching}
                  >
                    Refresh
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setIsRebuildIndexesConfirmOpen(true)}
                    disabled={rebuildIndexesMutation.isPending}
                    className="border-amber-500/40 text-amber-200 hover:bg-amber-500/10"
                  >
                    {rebuildIndexesMutation.isPending ? "Rebuilding..." : "Rebuild missing indexes"}
                  </Button>
                </div>
              </div>
              {mongoDiagnosticsQuery.isLoading ? (
                <div className="text-sm text-gray-400">Loading diagnostics...</div>
              ) : diagnostics.length === 0 ? (
                <div className="text-sm text-gray-400">No diagnostics available.</div>
              ) : (
                <div className="rounded-md border border-border/70 bg-card/60">
                  <Table>
                    <TableHeader>
                      <TableRow className="border-border/60">
                        <TableHead className="text-xs text-gray-400">Collection</TableHead>
                        <TableHead className="text-xs text-gray-400">Expected</TableHead>
                        <TableHead className="text-xs text-gray-400">Missing</TableHead>
                        <TableHead className="text-xs text-gray-400">Extra</TableHead>
                        <TableHead className="text-xs text-gray-400 text-right">Status</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {diagnostics.map((collection: MongoCollectionIndexStatus) => {
                        const missingCount = collection.missing.length;
                        const extraCount = collection.extra.length;
                        const statusLabel = collection.error
                          ? "Error"
                          : missingCount === 0
                            ? "OK"
                            : "Missing";
                        return (
                          <TableRow key={collection.name} className="border-border/50">
                            <TableCell className="font-mono text-xs text-gray-200">
                              {collection.name}
                            </TableCell>
                            <TableCell className="text-xs text-gray-300">
                              {collection.expected.length}
                            </TableCell>
                            <TableCell className="text-xs text-gray-300">
                              {collection.error ? (
                                <div className="space-y-1 text-rose-200">
                                  <div>—</div>
                                  <div className="rounded bg-rose-500/10 px-2 py-1 text-[10px]">
                                    {collection.error}
                                  </div>
                                </div>
                              ) : missingCount === 0 ? (
                                "0"
                              ) : (
                                <div className="space-y-1">
                                  <div className="text-amber-200">{missingCount}</div>
                                  <div className="space-y-1 text-[10px] text-amber-200">
                                    {collection.missing.map((item: MongoIndexInfo) => (
                                      <div
                                        key={JSON.stringify(item.key)}
                                        className="rounded bg-amber-500/10 px-2 py-1"
                                      >
                                        {JSON.stringify(item.key)}
                                      </div>
                                    ))}
                                  </div>
                                </div>
                              )}
                            </TableCell>
                            <TableCell className="text-xs text-gray-300">
                              {extraCount}
                            </TableCell>
                            <TableCell className="text-right">
                              <span
                                className={`rounded border px-2 py-0.5 text-xs ${
                                  collection.error
                                    ? "border-rose-400/40 text-rose-200 bg-rose-500/10"
                                    : missingCount === 0
                                      ? "border-emerald-400/40 text-emerald-200 bg-emerald-500/10"
                                      : "border-amber-400/40 text-amber-200 bg-amber-500/10"
                                }`}
                              >
                                {statusLabel}
                              </span>
                            </TableCell>
                          </TableRow>
                        );
                      })}
                    </TableBody>
                  </Table>
                </div>
              )}
            </SectionPanel>
          </>
        }
        filters={
          <DynamicFilters
            fields={filterFields}
            values={{ level, query, source, fromDate, toDate }}
            onChange={handleFilterChange}
            onReset={handleResetFilters}
            hasActiveFilters={Boolean(level !== "all" || query || source || fromDate || toDate)}
            gridClassName="md:grid-cols-5"
          />
        }
      >
        <div className="space-y-6">
          <SectionPanel variant="subtle" className="p-4">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <h2 className="text-lg font-semibold text-white">Metrics</h2>
                <p className="text-xs text-gray-400">
                  Metrics reflect the current filters.
                </p>
              </div>
              <div className="text-xs text-gray-500">
                {metrics?.generatedAt ? `Updated ${formatTimestamp(metrics.generatedAt)}` : "—"}
              </div>
            </div>
            {metricsQuery.isLoading ? (
              <div className="mt-4 text-sm text-gray-400">Loading metrics...</div>
            ) : !metrics ? (
              <div className="mt-4 text-sm text-gray-400">
                No metrics available yet.
              </div>
            ) : (
              <div className="mt-4 grid gap-4 md:grid-cols-3">
                <SectionPanel variant="subtle-compact" className="p-3">
                  <div className="text-xs text-gray-400">Totals</div>
                  <div className="mt-2 space-y-1 text-sm text-gray-200">
                    <div>Total: {metrics.total}</div>
                    <div>Last 24h: {metrics.last24Hours}</div>
                    <div>Last 7d: {metrics.last7Days}</div>
                  </div>
                </SectionPanel>
                <SectionPanel variant="subtle-compact" className="p-3">
                  <div className="text-xs text-gray-400">By level</div>
                  <div className="mt-2 space-y-1 text-sm text-gray-200">
                    <div className="text-red-300">Errors: {levels.error}</div>
                    <div className="text-yellow-300">Warnings: {levels.warn}</div>
                    <div className="text-blue-300">Info: {levels.info}</div>
                  </div>
                </SectionPanel>
                <SectionPanel variant="subtle-compact" className="p-3">
                  <div className="text-xs text-gray-400">Top sources</div>
                  {metrics.topSources.length === 0 ? (
                    <div className="mt-2 text-xs text-gray-500">No sources yet.</div>
                  ) : (
                    <div className="mt-2 space-y-1 text-xs text-gray-300">
                      {metrics.topSources.map((item: SystemLogMetrics["topSources"][number]) => (
                        <div key={item.source} className="flex items-center justify-between gap-2">
                          <span className="truncate">{item.source}</span>
                          <span className="text-gray-500">{item.count}</span>
                        </div>
                      ))}
                    </div>
                  )}
                  <div className="mt-3 text-xs text-gray-400">Top paths</div>
                  {metrics.topPaths.length === 0 ? (
                    <div className="mt-2 text-xs text-gray-500">No paths yet.</div>
                  ) : (
                    <div className="mt-2 space-y-1 text-xs text-gray-300">
                      {metrics.topPaths.map((item: SystemLogMetrics["topPaths"][number]) => (
                        <div key={item.path} className="flex items-center justify-between gap-2">
                          <span className="truncate">{item.path}</span>
                          <span className="text-gray-500">{item.count}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </SectionPanel>
              </div>
            )}
          </SectionPanel>

          <SectionPanel variant="subtle" className="p-4">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <h2 className="text-lg font-semibold text-white">AI Log Interpreter</h2>
                <p className="text-xs text-gray-400">
                  Summarizes error patterns and potential causes using your configured AI model or agent.
                </p>
              </div>
              <Button
                variant="outline"
                size="sm"
                onClick={() => runInsightMutation.mutate()}
                disabled={runInsightMutation.isPending}
              >
                {runInsightMutation.isPending ? "Running..." : "Run AI Interpretation"}
              </Button>
            </div>
            {insightsQuery.isLoading ? (
              <div className="mt-3 text-xs text-gray-400">Loading AI insights...</div>
            ) : insightsQuery.error ? (
              <div className="mt-3 text-xs text-red-400">{insightsQuery.error.message}</div>
            ) : (insightsQuery.data?.insights?.length ?? 0) === 0 ? (
              <div className="mt-3 text-xs text-gray-500">No AI insights yet.</div>
            ) : (
              <div className="mt-3 space-y-3">
                {insightsQuery.data?.insights.map((insight: AiInsightRecord) => (
                  <div key={insight.id} className="rounded-md border border-border/60 bg-gray-950/40 p-3 text-xs text-gray-300">
                    <div className="flex items-center justify-between gap-2">
                      <span className="text-[10px] uppercase text-gray-500">
                        {formatTimestamp(insight.createdAt)}
                      </span>
                      <span
                        className={`rounded border px-2 py-0.5 text-[10px] ${
                          insight.status === "ok"
                            ? "border-emerald-500/40 text-emerald-200"
                            : insight.status === "warning"
                              ? "border-amber-500/40 text-amber-200"
                              : "border-rose-500/40 text-rose-200"
                        }`}
                      >
                        {insight.status}
                      </span>
                    </div>
                    <div className="mt-2 text-sm text-white">{insight.summary}</div>
                    {insight.warnings.length > 0 ? (
                      <ul className="mt-2 list-disc space-y-1 pl-4 text-[11px] text-amber-200">
                        {insight.warnings.map((warning: string, index: number) => (
                          <li key={`${insight.id}-warn-${index}`}>{warning}</li>
                        ))}
                      </ul>
                    ) : null}
                  </div>
                ))}
              </div>
            )}
            <div className="mt-3 text-[10px] text-gray-500">
              Configure the AI model/agent in Settings → AI.
            </div>
          </SectionPanel>

          <SectionPanel variant="subtle" className="p-0">
            <div className="flex flex-wrap items-center justify-between gap-3 border-b border-border px-4 py-3 text-xs text-gray-400">
              <span>
                Showing {logs.length} of {total} logs
              </span>
              <Pagination
                page={page}
                totalPages={totalPages}
                onPageChange={setPage}
                className="scale-90 origin-right"
              />
            </div>
            {logsQuery.isLoading ? (
              <div className="px-4 py-8 text-sm text-gray-400">Loading logs...</div>
            ) : logs.length === 0 ? (
              <div className="px-4 py-8 text-sm text-gray-400">
                No system logs found.
              </div>
            ) : (
              <div className="divide-y divide-border">
                {logs.map((log: SystemLogRecord) => (
                  <div key={log.id} className="px-4 py-4">
                    <div className="flex flex-wrap items-center justify-between gap-3">
                      <div className="flex items-center gap-3">
                                                  <StatusBadge
                                                  status={log.level}
                                                  variant={log.level === "warn" ? "warning" : log.level as "info" | "success" | "warning" | "error"}
                                                />                        <span className="text-xs text-gray-400">
                          {formatTimestamp(log.createdAt)}
                        </span>
                      </div>
                      <div className="flex items-center gap-2">
                        {log.source ? (
                          <span className="text-xs text-gray-500">{log.source}</span>
                        ) : null}
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => interpretLogMutation.mutate(log.id)}
                          disabled={interpretLogMutation.isPending}
                          className="h-6 px-2 text-[10px]"
                        >
                          Interpret
                        </Button>
                      </div>
                    </div>
                    <div className="mt-2 text-sm text-gray-200">{log.message}</div>
                    {(log.path || log.method || log.statusCode) && (
                      <div className="mt-2 text-xs text-gray-500">
                        {log.method ? `${log.method} ` : ""}
                        {log.path ?? ""}
                        {log.statusCode ? ` • ${log.statusCode}` : ""}
                      </div>
                    )}
                    {log.context && getContextValue(log.context, "fingerprint") ? (
                      <div className="mt-2 text-xs text-gray-500">
                        Fingerprint:{" "}
                        <span className="font-mono text-gray-300">
                          {String(getContextValue(log.context, "fingerprint"))}
                        </span>
                      </div>
                    ) : null}
                    {(log.context || log.stack) && (
                      <details className="mt-2 text-xs text-gray-400">
                        <summary className="cursor-pointer hover:text-gray-200">
                          Details
                        </summary>
                        {logInterpretations[log.id] ? (
                          <SectionPanel variant="subtle-compact" className="mt-2 p-2 text-[11px] text-gray-300">
                            <div className="font-semibold text-gray-200">AI Interpretation</div>
                            <div className="mt-2 text-gray-300">
                              {logInterpretations[log.id]?.summary}
                            </div>
                            {logInterpretations[log.id]?.warnings?.length ? (
                              <ul className="mt-2 list-disc space-y-1 pl-4 text-[11px] text-amber-200">
                                {logInterpretations[log.id]?.warnings?.map((warning: string, index: number) => (
                                  <li key={`${log.id}-ai-${index}`}>{warning}</li>
                                ))}
                              </ul>
                            ) : null}
                          </SectionPanel>
                        ) : null}
                        {log.source === "client" && log.context ? (
                          <SectionPanel variant="subtle-compact" className="mt-2 p-2 text-[11px] text-gray-300">
                            <div className="font-semibold text-gray-200">Client context</div>
                            <div className="mt-2 grid gap-2 md:grid-cols-2">
                              <div>
                                <div className="text-gray-500">App</div>
                                <div>{String((getContextValue(log.context, "app.version") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Build</div>
                                <div>{String((getContextValue(log.context, "app.buildId") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Release</div>
                                <div>{String((getContextValue(log.context, "app.releaseChannel") as string | number | null) ?? "—")}</div>
                              </div>
                              <div>
                                <div className="text-gray-500">User</div>
                                <div>{String((getContextValue(log.context, "user.email") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Role</div>
                                <div>{String((getContextValue(log.context, "user.role") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Route</div>
                                <div>{String((getContextValue(log.context, "route") as string | number | null) ?? "—")}</div>
                              </div>
                              <div>
                                <div className="text-gray-500">Device</div>
                                <div>{String((getContextValue(log.context, "device.platform") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Memory</div>
                                <div>{String((getContextValue(log.context, "device.deviceMemory") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Cores</div>
                                <div>{String((getContextValue(log.context, "device.hardwareConcurrency") as string | number | null) ?? "—")}</div>
                              </div>
                              <div>
                                <div className="text-gray-500">Network</div>
                                <div>{String((getContextValue(log.context, "network.effectiveType") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">Downlink</div>
                                <div>{String((getContextValue(log.context, "network.downlink") as string | number | null) ?? "—")}</div>
                                <div className="text-gray-500">RTT</div>
                                <div>{String((getContextValue(log.context, "network.rtt") as string | number | null) ?? "—")}</div>
                              </div>
                            </div>
                          </SectionPanel>
                        ) : null}
                        {log.stack && (
                          <pre className="mt-2 whitespace-pre-wrap rounded border border-border bg-card p-2 text-[11px] text-gray-300">
                            {log.stack}
                          </pre>
                        )}
                        {log.context && (
                          <pre className="mt-2 whitespace-pre-wrap rounded border border-border bg-card p-2 text-[11px] text-gray-300">
                            {JSON.stringify(log.context, null, 2)}
                          </pre>
                        )}
                      </details>
                    )}
                  </div>
                ))}
              </div>
            )}
          </SectionPanel>
        </div>
      </ListPanel>
    </div>
  );
}

"use client";

import { DynamicFilters, SelectionBar, DropdownMenuItem, type FilterField } from "@/shared/ui";
import { memo, useCallback, useMemo } from "react";



import { Store } from "lucide-react";

import type { ProductWithImages } from "@/features/products/types";
import type { RowSelectionState } from "@tanstack/react-table";

interface ProductFiltersProps {
  search: string;
  setSearch: (value: string) => void;
  sku: string;
  setSku: (value: string) => void;
  minPrice: number | undefined;
  setMinPrice: (value: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (value: number | undefined) => void;
  startDate: string;
  setStartDate: (value: string) => void;
  endDate: string;
  setEndDate: (value: string) => void;
}

export const ProductFilters = memo(function ProductFilters({
  search,
  setSearch,
  sku,
  setSku,
  minPrice,
  setMinPrice,
  maxPrice,
  setMaxPrice,
  startDate,
  setEndDate,
  endDate,
  setStartDate,
}: ProductFiltersProps): React.JSX.Element {
  const hasActiveFilters = Boolean(search || sku || minPrice || maxPrice || startDate || endDate);

  const filterFields: FilterField[] = useMemo(() => [
    { key: "search", label: "Name", type: "search", placeholder: "Search by name..." },
    { key: "sku", label: "SKU", type: "search", placeholder: "Search by SKU..." },
    { key: "minPrice", label: "Min Price", type: "number", placeholder: "Min price" },
    { key: "maxPrice", label: "Max Price", type: "number", placeholder: "Max price" },
    { key: "startDate", label: "From Date", type: "date" },
    { key: "endDate", label: "To Date", type: "date" },
  ], []);

  const handleFilterChange = useCallback((key: string, value: any): void => {
    if (key === "search") setSearch(value);
    if (key === "sku") setSku(value);
    if (key === "minPrice") setMinPrice(value ? parseInt(value, 10) : undefined);
    if (key === "maxPrice") setMaxPrice(value ? parseInt(value, 10) : undefined);
    if (key === "startDate") setStartDate(value);
    if (key === "endDate") setEndDate(value);
  }, [setSearch, setSku, setMinPrice, setMaxPrice, setStartDate, setEndDate]);

  const handleResetFilters = (): void => {
    setSearch("");
    setSku("");
    setMinPrice(undefined);
    setMaxPrice(undefined);
    setStartDate("");
    setEndDate("");
  };

  return (
    <DynamicFilters
      fields={filterFields}
      values={{ search, sku, minPrice, maxPrice, startDate, endDate }}
      onChange={handleFilterChange}
      onReset={handleResetFilters}
      hasActiveFilters={hasActiveFilters}
      gridClassName="sm:grid-cols-2 lg:grid-cols-6"
    />
  );
});

interface ProductSelectionActionsProps {
  data?: ProductWithImages[];
  rowSelection?: RowSelectionState;
  setRowSelection?: (selection: RowSelectionState) => void;
  onSelectAllGlobal?: (() => Promise<void>) | undefined;
  loadingGlobal?: boolean | undefined;
  onDeleteSelected?: (() => Promise<void>) | undefined;
  onAddToMarketplace?: (() => void) | undefined;
}

export const ProductSelectionActions = memo(function ProductSelectionActions({
  data = [],
  rowSelection = {},
  setRowSelection = (): void => {},
  onSelectAllGlobal,
  loadingGlobal,
  onDeleteSelected,
  onAddToMarketplace,
}: ProductSelectionActionsProps) {
  const getRowId = useCallback((p: ProductWithImages) => p.id, []);

  return (
    <SelectionBar
      data={data}
      getRowId={getRowId}
      rowSelection={rowSelection}
      setRowSelection={setRowSelection}
      {...(onSelectAllGlobal ? { onSelectAllGlobal } : {})}
      {...(loadingGlobal !== undefined ? { loadingGlobal } : {})}
      {...(onDeleteSelected ? { onDeleteSelected } : {})}
      className="border-t pt-3"
      actions={
        <DropdownMenuItem
          onClick={() => {
            if (onAddToMarketplace) onAddToMarketplace();
          }}
          className="cursor-pointer gap-2"
        >
          <Store className="h-4 w-4" />
          Add to Marketplace
        </DropdownMenuItem>
      }
    />
  );
});

"use client";

import { Button, UnifiedSelect, useToast, Pagination, ConfirmDialog, SectionPanel, SectionHeader } from "@/shared/ui";
import { memo, useState } from "react";
import {
  PlusIcon,
  Package,
} from "lucide-react";
import { ICON_LIBRARY_MAP } from "@/features/icons";
import { TriggerButtonBar } from "@/features/ai/ai-paths/components/trigger-buttons/TriggerButtonBar";


import type { Catalog } from "@/features/products/types";
import type { ProductDraft } from "@/features/products/types/drafts";

interface ProductListHeaderProps {
  onCreateProduct: () => void;
  onCreateFromDraft?: (draftId: string) => void;
  activeDrafts?: ProductDraft[];
  page: number;
  totalPages: number;
  setPage: (page: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  nameLocale: "name_en" | "name_pl" | "name_de";
  setNameLocale: (locale: "name_en" | "name_pl" | "name_de") => void;
  languageOptions: Array<{ value: "name_en" | "name_pl" | "name_de"; label: string }>;
  currencyCode: string;
  setCurrencyCode: (code: string) => void;
  currencyOptions: string[];
  catalogFilter: string;
  setCatalogFilter: (filter: string) => void;
  catalogs: Catalog[];
  showHeader?: boolean;
}

export const ProductListHeader = memo(function ProductListHeader({
  onCreateProduct,
  onCreateFromDraft,
  activeDrafts = [],
  page,
  totalPages,
  setPage,
  pageSize,
  setPageSize,
  nameLocale,
  setNameLocale,
  languageOptions,
  currencyCode,
  setCurrencyCode,
  currencyOptions,
  catalogFilter,
  setCatalogFilter,
  catalogs,
  showHeader = true,
}: ProductListHeaderProps) {
  const { toast } = useToast();
  const [showBase64AllConfirm, setShowBase64AllConfirm] = useState(false);
  const [isConvertingAll, setIsConvertingAll] = useState(false);

  const handleConvertAllBase64 = async (): Promise<void> => {
    setIsConvertingAll(true);
    try {
      const res = await fetch("/api/products/images/base64/all", { method: "POST" });
      if (!res.ok) {
        const payload = (await res.json().catch(() => ({}))) as { error?: string };
        throw new Error(payload.error || "Failed to convert images");
      }
      toast("Base64 images generated for all products.", { variant: "success" });
    } catch (error) {
      toast(
        error instanceof Error ? error.message : "An error occurred during conversion",
        { variant: "error" }
      );
    } finally {
      setIsConvertingAll(false);
      setShowBase64AllConfirm(false);
    }
  };

  return (
    <div className="space-y-4">
      {showHeader && (
        <SectionHeader
          title="Products"
          actions={
            <div className="flex items-center gap-3">
              <TriggerButtonBar location="product_list" entityType="product" />
            </div>
          }
          eyebrow={
            <div className="flex flex-wrap items-center gap-2 mb-2">
              <Button
                onClick={onCreateProduct}
                className="h-14 w-14 rounded-full border border-white/20 p-0 hover:border-white/40"
                aria-label="Create new product"
              >
                <PlusIcon className="h-6 w-6" />
              </Button>
              <div className="flex flex-wrap items-center gap-1.5">
                {activeDrafts.map((draft: ProductDraft) => {
                  const IconComponent = draft.icon ? ICON_LIBRARY_MAP[draft.icon] : null;
                  return (
                    <Button
                      key={draft.id}
                      onClick={() => onCreateFromDraft?.(draft.id)}
                      className="h-8 w-8 rounded-full border border-white/20 bg-transparent p-0 text-white hover:border-white/40 hover:bg-white/10"
                      aria-label={`Create product from ${draft.name}`}
                      title={draft.name}
                    >
                      {IconComponent ? (
                        <IconComponent className="h-3.5 w-3.5" />
                      ) : (
                        <Package className="h-3.5 w-3.5" />
                      )}
                    </Button>
                  );
                })}
              </div>
            </div>
          }
        />
      )}

      {/* Controls section */}
      <SectionPanel className="flex flex-col gap-4 p-4 sm:flex-row sm:items-center sm:justify-between">
        <Pagination
          page={page}
          totalPages={totalPages}
          onPageChange={setPage}
          pageSize={pageSize}
          onPageSizeChange={setPageSize}
          pageSizeOptions={[12, 24, 48, 96]}
          showPageSize
        />

        {/* Filter selectors */}
        <div className="flex flex-col gap-2 sm:flex-row sm:gap-3">
          <UnifiedSelect
            value={nameLocale}
            onValueChange={(value: string) =>
              setNameLocale(value as "name_en" | "name_pl" | "name_de")
            }
            options={languageOptions}
            placeholder="Language"
            triggerClassName="w-full sm:w-44"
            ariaLabel="Select product name language"
          />

          <UnifiedSelect
            value={currencyCode}
            onValueChange={setCurrencyCode}
            options={currencyOptions.map((code: string) => ({ value: code, label: code }))}
            placeholder="Currency"
            triggerClassName="w-full sm:w-32"
            ariaLabel="Select currency"
          />

          <UnifiedSelect
            value={catalogFilter}
            onValueChange={setCatalogFilter}
            options={[
              { value: "all", label: "All catalogs" },
              { value: "unassigned", label: "Unassigned" },
              ...catalogs.map((catalog: Catalog) => ({ value: catalog.id, label: catalog.name }))
            ]}
            placeholder="Catalog"
            triggerClassName="w-full sm:w-52"
            ariaLabel="Filter by catalog"
          />
        </div>

        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant="outline"
            onClick={() => setShowBase64AllConfirm(true)}
            disabled={isConvertingAll}
          >
            {isConvertingAll ? "Converting..." : "Convert all products"}
          </Button>
        </div>
      </SectionPanel>

      <ConfirmDialog
        open={showBase64AllConfirm}
        onOpenChange={setShowBase64AllConfirm}
        title="Generate Base64 images for all products?"
        description="This will generate Base64 images for every product and may take time on large catalogs."
        onConfirm={() => void handleConvertAllBase64()}
        confirmText="Convert"
        variant="success"
        loading={isConvertingAll}
      />
    </div>
  );
});

"use client";


import React from "react";

import {
  Input,
  Label,
  Textarea,
  Checkbox,
  useToast,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Badge,
  Alert,
  FormModal,
} from "@/shared/ui";
import type { Catalog, PriceGroup } from "@/features/products/types";
import type { Language } from "@/shared/types/internationalization";
import { useSaveCatalogMutation } from "@/features/products/hooks/useProductSettingsQueries";
import { logClientError } from "@/shared/utils/observability/client-error-logger";

interface CatalogModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  catalog?: Catalog | null;
  languages: Language[];
  languagesLoading: boolean;
  languagesError: string | null;
  priceGroups: PriceGroup[];
  loadingGroups: boolean;
  defaultGroupId: string;
}

export function CatalogModal({
  isOpen,
  onClose,
  onSuccess,
  catalog,
  languages,
  languagesLoading,
  languagesError,
  priceGroups,
  loadingGroups,
  defaultGroupId,
}: CatalogModalProps): React.JSX.Element {
  const { toast } = useToast();
  const saveMutation = useSaveCatalogMutation();
  const [error, setError] = React.useState<string | null>(null);
  const [form, setForm] = React.useState({
    name: "",
    description: "",
    isDefault: false,
  });
  const [selectedLanguageIds, setSelectedLanguageIds] = React.useState<
    string[]
  >([]);
  const [defaultLanguageId, setDefaultLanguageId] = React.useState("");
  const [catalogPriceGroupIds, setCatalogPriceGroupIds] = React.useState<
    string[]
  >([]);
  const [catalogDefaultPriceGroupId, setCatalogDefaultPriceGroupId] =
    React.useState("");
  const [languageQuery, setLanguageQuery] = React.useState("");

  React.useEffect(() => {
    if (catalog) {
      setForm({
        name: catalog.name,
        description: catalog.description ?? "",
        isDefault: catalog.isDefault,
      });
      const nextLanguageIds = catalog.languageIds ?? [];
      setSelectedLanguageIds(nextLanguageIds);
      setDefaultLanguageId(
        catalog.defaultLanguageId ?? nextLanguageIds[0] ?? "",
      );
      const nextPriceGroupIds = catalog.priceGroupIds?.length
        ? catalog.priceGroupIds
        : defaultGroupId
          ? [defaultGroupId]
          : [];
      setCatalogPriceGroupIds(nextPriceGroupIds);
      setCatalogDefaultPriceGroupId(
        catalog.defaultPriceGroupId ??
          nextPriceGroupIds[0] ??
          defaultGroupId ??
          "",
      );
    } else {
      setForm({
        name: "",
        description: "",
        isDefault: false,
      });
      setSelectedLanguageIds([]);
      setDefaultLanguageId("");
      setCatalogPriceGroupIds(defaultGroupId ? [defaultGroupId] : []);
      setCatalogDefaultPriceGroupId(defaultGroupId ?? "");
    }
    setError(null);
    setLanguageQuery("");
  }, [catalog, defaultGroupId]);

  const handleSubmit = async (): Promise<void> => {
    if (saveMutation.isPending) return;
    const name = form.name.trim();
    if (!name) {
      toast("Catalog name is required.", { variant: "error" });
      return;
    }
    if (selectedLanguageIds.length === 0) {
      toast("Select at least one language.", { variant: "error" });
      return;
    }
    if (
      !defaultLanguageId ||
      !selectedLanguageIds.includes(defaultLanguageId)
    ) {
      toast("Select a default language.", { variant: "error" });
      return;
    }
    if (catalogPriceGroupIds.length === 0) {
      toast("Select at least one price group.", { variant: "error" });
      return;
    }
    if (
      !catalogDefaultPriceGroupId ||
      !catalogPriceGroupIds.includes(catalogDefaultPriceGroupId)
    ) {
      toast("Select a default price group.", { variant: "error" });
      return;
    }

    try {
      await saveMutation.mutateAsync({
        ...(catalog?.id ? { id: catalog.id } : {}),
        data: {
          name,
          description: form.description.trim(),
          languageIds: selectedLanguageIds,
          defaultLanguageId,
          priceGroupIds: catalogPriceGroupIds,
          defaultPriceGroupId: catalogDefaultPriceGroupId,
          isDefault: form.isDefault,
        },
      });

      toast("Catalog saved.", { variant: "success" });
      onSuccess();
    } catch (err) {
      logClientError(err, { context: { source: "CatalogModal", action: "saveCatalog", catalogId: catalog?.id } });
      setError(err instanceof Error ? err.message : "Failed to save catalog.");
    }
  };

  const availableLanguages = React.useMemo((): Language[] => {
    const query = languageQuery.trim().toLowerCase();
    return languages.filter(
      (l) =>
        !selectedLanguageIds.includes(l.id) &&
        (!query ||
          l.name.toLowerCase().includes(query) ||
          l.code.toLowerCase().includes(query)),
    );
  }, [languages, selectedLanguageIds, languageQuery]);

  const toggleLanguage = (id: string): void => {
    setSelectedLanguageIds((prev) => {
      const next = prev.includes(id)
        ? prev.filter((i) => i !== id)
        : [...prev, id];
      if (!next.includes(defaultLanguageId))
        setDefaultLanguageId(next[0] ?? "");
      return next;
    });
  };

  const moveLanguage = (id: string, direction: "up" | "down"): void => {
    setSelectedLanguageIds((prev) => {
      const idx = prev.indexOf(id);
      if (idx === -1) return prev;
      const nextIdx = direction === "up" ? idx - 1 : idx + 1;
      if (nextIdx < 0 || nextIdx >= prev.length) return prev;
      const next = [...prev];
      [next[idx], next[nextIdx]] = [next[nextIdx]!, next[idx]!];
      return next;
    });
  };

  const togglePriceGroup = (id: string): void => {
    setCatalogPriceGroupIds((prev) => {
      const next = prev.includes(id)
        ? prev.filter((i) => i !== id)
        : [...prev, id];
      if (!next.includes(catalogDefaultPriceGroupId))
        setCatalogDefaultPriceGroupId(next[0] ?? "");
      return next;
    });
  };

  return (
    <FormModal
      isOpen={isOpen}
      onClose={onClose}
      title={catalog ? "Edit Catalog" : "Create Catalog"}
      onSave={() => {
        void handleSubmit();
      }}
      isSaving={saveMutation.isPending}
      saveText={catalog ? "Update" : "Create"}
      cancelText="Close"
      size="lg"
    >
      <div className="space-y-6">
        {error && (
          <Alert variant="error" className="p-3 text-xs">
            {error}
          </Alert>
        )}

        <div className="grid gap-4">
          <div className="space-y-2">
            <Label htmlFor="catalog-name">Name</Label>
            <Input
              id="catalog-name"
              value={form.name}
              onChange={(e) =>
                setForm((p) => ({ ...p, name: e.target.value }))
              }
              placeholder="e.g. Main Store"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="catalog-desc">Description</Label>
            <Textarea
              id="catalog-desc"
              value={form.description}
              onChange={(e) =>
                setForm((p) => ({ ...p, description: e.target.value }))
              }
              placeholder="Optional description..."
              rows={2}
            />
          </div>
          <Label className="flex items-center gap-2 text-gray-300">
            <Checkbox
              checked={form.isDefault}
              onCheckedChange={(v) =>
                setForm((p) => ({ ...p, isDefault: Boolean(v) }))
              }
            />
            Set as default catalog
          </Label>
        </div>

        <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
          <Label className="text-sm font-semibold text-white">
            Languages
          </Label>
          {languagesLoading ? (
            <p className="text-xs text-gray-500">Loading languages...</p>
          ) : languagesError ? (
            <p className="text-xs text-red-400">{languagesError}</p>
          ) : (
            <div className="space-y-4">
              <Input
                placeholder="Search languages..."
                value={languageQuery}
                onChange={(e) => setLanguageQuery(e.target.value)}
              />

              <div className="space-y-1">
                {selectedLanguageIds.length === 0 ? (
                  <p className="text-xs text-gray-500">
                    No languages selected.
                  </p>
                ) : (
                  selectedLanguageIds.map((id, index) => {
                    const lang = languages.find((l) => l.id === id);
                    if (!lang) return null;
                    return (
                      <div
                        key={id}
                        className="flex items-center justify-between rounded-md border bg-gray-900 px-3 py-1.5 text-xs text-gray-200"
                      >
                        <div className="flex items-center gap-2">
                          <span className="text-gray-500 w-4">
                            {index + 1}.
                          </span>
                          <span>
                            {lang.name} ({lang.code})
                          </span>
                          {id === defaultLanguageId && (
                            <Badge variant="success">
                              Default
                            </Badge>
                          )}
                        </div>
                        <div className="flex gap-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6"
                            onClick={() => moveLanguage(id, "up")}
                            disabled={index === 0}
                          >
                            ↑
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6"
                            onClick={() => moveLanguage(id, "down")}
                            disabled={
                              index === selectedLanguageIds.length - 1
                            }
                          >
                            ↓
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6 text-red-400"
                            onClick={() => toggleLanguage(id)}
                          >
                            ×
                          </Button>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>

              <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                {availableLanguages.map((lang) => (
                  <Button
                    key={lang.id}
                    variant="ghost"
                    className="w-full justify-between h-8 px-2"
                    onClick={() => toggleLanguage(lang.id)}
                  >
                    <span>
                      {lang.name} ({lang.code})
                    </span>
                    <span className="text-gray-500">Add</span>
                  </Button>
                ))}
              </div>

              <div className="space-y-2">
                <Label className="text-xs text-gray-400">
                  Default language
                </Label>
                <Select
                  value={defaultLanguageId}
                  onValueChange={(v) => setDefaultLanguageId(v)}
                  disabled={selectedLanguageIds.length === 0}
                >
                  <SelectTrigger className="w-full bg-gray-900 border-border text-xs text-white">
                    <SelectValue placeholder="Select default language" />
                  </SelectTrigger>
                  <SelectContent>
                    {selectedLanguageIds.map((id) => {
                      const lang = languages.find((l) => l.id === id);
                      return (
                        <SelectItem key={id} value={id}>
                          {lang?.name} ({lang?.code})
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
            </div>
          )}
        </div>

        <div className="rounded-md border border-border bg-card/70 p-4 space-y-4">
          <Label className="text-sm font-semibold text-white">
            Price Groups
          </Label>
          {loadingGroups ? (
            <p className="text-xs text-gray-500">Loading groups...</p>
          ) : (
            <div className="space-y-4">
              <div className="flex flex-wrap gap-2">
                {catalogPriceGroupIds.map((id) => {
                  const group = priceGroups.find((g) => g.id === id);
                  return (
                    <Button
                      key={id}
                      variant="secondary"
                      className="h-7 rounded-full px-3 text-xs"
                      onClick={() => togglePriceGroup(id)}
                    >
                      {group?.name ?? id}{" "}
                      <span className="ml-1 text-gray-500">×</span>
                    </Button>
                  );
                })}
              </div>

              <div className="max-h-32 overflow-y-auto rounded-md border border-border bg-gray-900 p-2 text-xs">
                {priceGroups.map((group) => (
                  <Button
                    key={group.id}
                    variant="ghost"
                    className="w-full justify-between h-8 px-2"
                    onClick={() => togglePriceGroup(group.id)}
                  >
                    <span>
                      {group.name} ({group.currencyCode})
                    </span>
                    <span>
                      {catalogPriceGroupIds.includes(group.id)
                        ? "Remove"
                        : "Add"}
                    </span>
                  </Button>
                ))}
              </div>

              <div className="space-y-2">
                <Label className="text-xs text-gray-400">
                  Default price group
                </Label>
                <Select
                  value={catalogDefaultPriceGroupId}
                  onValueChange={(v) =>
                    setCatalogDefaultPriceGroupId(v)
                  }
                  disabled={catalogPriceGroupIds.length === 0}
                >
                  <SelectTrigger className="w-full bg-gray-900 border-border text-xs text-white">
                    <SelectValue placeholder="Select default price group" />
                  </SelectTrigger>
                  <SelectContent>
                    {catalogPriceGroupIds.map((id) => {
                      const group = priceGroups.find((g) => g.id === id);
                      return (
                        <SelectItem key={id} value={id}>
                          {group?.name}
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
            </div>
          )}
        </div>
      </div>
    </FormModal>
  );
}

"use client";



import * as React from "react";

import {
  Button,
  Input,
  Label,
  Checkbox,
  Textarea,
  RadioGroup,
  RadioGroupItem,
  useToast,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui";
import { FormModal } from "@/shared/components/FormModal";
import type { PriceGroup, PriceGroupType } from "@/features/products/types";
import type { CurrencyOption } from "@/shared/types/internationalization";
import { useSavePriceGroupMutation } from "@/features/products/hooks/useProductSettingsQueries";
import { logClientError } from "@/features/observability";

interface PriceGroupModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  priceGroup?: PriceGroup | null;
  currencyOptions: CurrencyOption[];
  loadingCurrencies: boolean;
  priceGroups: PriceGroup[];
}

export function PriceGroupModal({
  isOpen,
  onClose,
  onSuccess,
  priceGroup,
  currencyOptions,
  loadingCurrencies,
  priceGroups,
}: PriceGroupModalProps): React.JSX.Element {
  const { toast } = useToast();
  const saveMutation = useSavePriceGroupMutation();
  const [form, setForm] = React.useState({
    isDefault: false,
    groupId: "",
    name: "",
    description: "",
    currencyId: "",
    groupType: "standard" as PriceGroupType,
    basePriceField: "price",
    sourceGroupId: "",
    priceMultiplier: 1,
    addToPrice: 0,
  });

  React.useEffect(() => {
    if (priceGroup) {
      setForm({
        isDefault: priceGroup.isDefault,
        groupId: priceGroup.groupId,
        name: priceGroup.name,
        description: priceGroup.description ?? "",
        currencyId: priceGroup.currencyId,
        groupType: priceGroup.groupType,
        basePriceField: priceGroup.basePriceField,
        sourceGroupId: priceGroup.sourceGroupId ?? "",
        priceMultiplier: priceGroup.priceMultiplier,
        addToPrice: priceGroup.addToPrice,
      });
    } else {
      const pln = currencyOptions.find((c) => c.code === "PLN")?.id || "";
      setForm({
        isDefault: false,
        groupId: `PG-${Math.random().toString(36).slice(2, 8).toUpperCase()}`,
        name: "",
        description: "",
        currencyId: pln,
        groupType: "standard",
        basePriceField: "price",
        sourceGroupId: "",
        priceMultiplier: 1,
        addToPrice: 0,
      });
    }
  }, [priceGroup, currencyOptions]);

  const handleSubmit = async (): Promise<void> => {
    if (!form.groupId.trim() || !form.name.trim() || !form.currencyId) {
      toast("Required fields missing.", { variant: "error" });
      return;
    }
    if (form.groupType === "dependent" && !form.sourceGroupId) {
      toast("Source price group is required for dependent groups.", {
        variant: "error",
      });
      return;
    }

    try {
      await saveMutation.mutateAsync({
        ...(priceGroup?.id ? { id: priceGroup.id } : {}),
        data: {
          ...form,
          groupId: form.groupId.trim(),
          name: form.name.trim(),
          description: form.description.trim(),
          sourceGroupId: form.sourceGroupId || null,
          groupType: form.groupType,
        },
      });

      toast("Price group saved.", { variant: "success" });
      onSuccess();
    } catch (err) {
      logClientError(err, { context: { source: "PriceGroupModal", action: "savePriceGroup", priceGroupId: priceGroup?.id } });
      toast("Failed to save price group.", { variant: "error" });
    }
  };

  return (
    <FormModal
      isOpen={isOpen}
      onClose={onClose}
      title={priceGroup ? "Edit Price Group" : "Create Price Group"}
      onSave={() => {
        void handleSubmit();
      }}
      isSaving={saveMutation.isPending}
      saveText={priceGroup ? "Update" : "Create"}
      cancelText="Close"
      size="lg"
    >
      <div className="space-y-4">
        <Label className="flex items-center gap-2 text-sm text-gray-300">
          <Checkbox
            checked={form.isDefault}
            onCheckedChange={(v) =>
